package com.jdmedia.controller;
import com.jdmedia.model.*;import com.jdmedia.service.AppContext;import javafx.fxml.FXML;import javafx.scene.control.*;
public final class SummaryController {private static ConversionOptions options;private final AppContext context;@FXML private Label filesLabel,descriptionLabel,estimateLabel;@FXML private ComboBox<ConversionPreset> qualityBox;public SummaryController(AppContext context){this.context=context;}public static void setOptions(ConversionOptions value){options=value;}public static ConversionOptions options(){return options;}@FXML public void initialize(){filesLabel.setText(AnalysisController.media().size()+" archivo(s) listo(s) para convertir");qualityBox.getItems().setAll(ConversionPreset.values());qualityBox.setValue(fromOptions());qualityBox.valueProperty().addListener((o,a,b)->showEstimate(b));showEstimate(qualityBox.getValue());}private void showEstimate(ConversionPreset preset){long total=AnalysisController.media().stream().mapToLong(MediaFile::sizeBytes).sum();long estimated=Math.round(total*preset.estimatedRemaining());descriptionLabel.setText(preset.description()+". La aplicación optimizará automáticamente si el resultado ocupa más que el original.");estimateLabel.setText("Estimación orientativa: "+size(total)+" → aproximadamente "+size(estimated)+".");}@FXML private void start(){ConversionPreset p=qualityBox.getValue();String profile=p==ConversionPreset.CLASSIC_LIBRARY?"classic":"medium";options=new ConversionOptions(profile,p.crf(),options.audioStreamIndexes(),options.subtitles(),false,options.convertHdrToSdr());context.navigation().show("conversion-view.fxml");}@FXML private void back(){context.navigation().show("analysis-view.fxml");}private ConversionPreset fromOptions(){if("classic".equals(options.preset()))return ConversionPreset.CLASSIC_LIBRARY;return options.crf()<=20?ConversionPreset.HIGH_QUALITY:options.crf()>=27?ConversionPreset.HIGH_COMPRESSION:ConversionPreset.BALANCED;}private String size(long b){return String.format("%.2f GB",b/1_073_741_824d);}}
